command:
bash -lc 'REPO_ROOT=${PROJECT_DIR:-$(pwd)}; cd "$REPO_ROOT"; bash agent-eval/scripts/prepare-fast-gate.sh >/dev/null; TMP_ROOT=$(mktemp -d); trap "rm -rf $TMP_ROOT" EXIT; mkdir -p "$TMP_ROOT/home"; cat > "$TMP_ROOT/.armature.json" <<EOF
{
  "providers": {
    "dummy": {
      "apiKey": "test-dummy-key",
      "defaultModel": "dummy-model"
    }
  },
  "defaultProvider": "dummy"
}
EOF
OUTPUT=$(cd "$TMP_ROOT" && env -i PATH="$PATH" HOME="$TMP_ROOT/home" ARMATURE_HOME="$TMP_ROOT/home/.armature" node "$REPO_ROOT/dist/bin/armature.js" run "say hello" --provider dummy --mission 2>&1; STATUS=$?; printf "status=%s\n%s\n" "$STATUS" "$OUTPUT"); printf "%s\n" "$OUTPUT"; printf "%s" "$OUTPUT" | grep -q "status=1"'
